   602→fn test_git_init_colocated_dirty_working_copy() {
   603→    let test_env = TestEnvironment::default();
   604→    let work_dir = test_env.work_dir("repo");
   605→    let git_repo = init_git_repo(work_dir.root(), false);
   606→
   607→    let mut index_manager = git::IndexManager::new(&git_repo);
   608→
   609→    index_manager.add_file("new-staged-file", b"new content");
   610→    index_manager.add_file("some-file", b"new content");
   611→    index_manager.sync_index();
   612→
   613→    work_dir.write_file("unstaged-file", "new content");
   614→    insta::assert_debug_snapshot!(git::status(&git_repo), @r#"
   615→    [
   616→        GitStatus {
   617→            path: "new-staged-file",
   618→            status: Index(
   619→                Addition,
   620→            ),
   621→        },
   622→        GitStatus {
   623→            path: "some-file",
   624→            status: Index(
   625→                Modification,
   626→            ),
   627→        },
   628→        GitStatus {
   629→            path: "unstaged-file",
   630→            status: Worktree(
   631→                Added,
   632→            ),
   633→        },
   634→    ]
   635→    "#);
   636→
   637→    let output = work_dir.run_jj(["git", "init", "--git-repo", "."]);
   638→    insta::assert_snapshot!(output, @r#"
   639→    ------- stderr -------
   640→    Done importing changes from the underlying Git repo.
   641→    Initialized repo in "."
   642→    [EOF]
   643→    "#);
   644→
   645→    // Working-copy changes should have been snapshotted.
   646→    let output = work_dir.run_jj(["log", "-s", "--ignore-working-copy"]);
   647→    insta::assert_snapshot!(output, @r"
   648→    @  sqpuoqvx test.user@example.com 2001-02-03 08:05:07 6efc2a53
   649→    │  (no description set)
   650→    │  C {some-file => new-staged-file}
   651→    │  M some-file
   652→    │  C {some-file => unstaged-file}
   653→    ○  nntyzxmz someone@example.org 1970-01-01 11:00:00 my-bookmark git_head() e80a42cc
   654→    │  My commit message
   655→    │  A some-file
   656→    ◆  zzzzzzzz root() 00000000
   657→    [EOF]
   658→    ");
   659→
   660→    // Git index should be consistent with the working copy parent. With the
   661→    // current implementation, the index is unchanged. Since jj created new
   662→    // working copy commit, it's also okay to update the index reflecting the
   663→    // working copy commit or the working copy parent.
   664→    insta::assert_debug_snapshot!(git::status(&git_repo), @r#"
   665→    [
   666→        GitStatus {
   667→            path: ".jj/.gitignore",
   668→            status: Worktree(
   669→                Ignored,
   670→            ),
   671→        },
   672→        GitStatus {
   673→            path: ".jj/repo",
   674→            status: Worktree(
   675→                Ignored,
   676→            ),
   677→        },
   678→        GitStatus {
   679→            path: ".jj/working_copy",
   680→            status: Worktree(
   681→                Ignored,
   682→            ),
   683→        },
   684→        GitStatus {
   685→            path: "new-staged-file",
   686→            status: Index(
   687→                Addition,
   688→            ),
   689→        },
   690→        GitStatus {
   691→            path: "some-file",
   692→            status: Index(
   693→                Modification,
   694→            ),
   695→        },
   696→        GitStatus {
   697→            path: "unstaged-file",
   698→            status: Worktree(
   699→                IntentToAdd,
   700→            ),
   701→        },
   702→    ]
   703→    "#);
   704→}
