// Test case to reproduce the trunk() alias bug
// This test verifies that trunk() alias should prefer upstream over origin

use std::fs;
use std::path::Path;
use tempfile::TempDir;

fn main() {
    // Create a temporary directory for our test
    let temp_dir = TempDir::new().unwrap();
    let test_dir = temp_dir.path();

    // Initialize a git repository
    let git_repo = gix::init(test_dir).unwrap();

    // Create a commit and set up both origin and upstream remotes
    let commit_result = git::add_commit(
        &git_repo,
        "refs/heads/main",
        "test.txt",
        b"test content",
        "Initial commit",
        &[],
    );

    // Set up origin/HEAD
    git::set_symbolic_reference(
        &git_repo,
        "refs/remotes/origin/HEAD",
        "refs/remotes/origin/main",
    );

    // Set up upstream/HEAD (this is the key part - upstream should be preferred)
    git::set_symbolic_reference(
        &git_repo,
        "refs/remotes/upstream/HEAD",
        "refs/remotes/upstream/main",
    );

    // Now run jj git init --colocate
    let output = std::process::Command::new("jj")
        .args(["git", "init", "--colocate"])
        .current_dir(test_dir)
        .output()
        .expect("Failed to run jj git init");

    // Check the output to see which remote trunk() alias was set to
    let stderr = String::from_utf8_lossy(&output.stderr);
    println!("jj git init output:\n{}", stderr);

    // Check the config to see what trunk() alias was set to
    let config_path = test_dir.join(".jj").join("repo").join("config.toml");
    if config_path.exists() {
        let config_content = fs::read_to_string(&config_path).unwrap();
        println!("Config content:\n{}", config_content);

        // The bug: currently trunk() will be set to main@origin
        // But it should be set to main@upstream since upstream exists
        if config_content.contains("trunk() = \"main@origin\"") {
            println!("BUG REPRODUCED: trunk() alias is set to origin instead of upstream");
        } else if config_content.contains("trunk() = \"main@upstream\"") {
            println!("BUG FIXED: trunk() alias correctly set to upstream");
        }
    }
}

