// Test to verify the trunk() alias fix
// This test creates a git repo with both origin and upstream remotes
// and verifies that trunk() alias is set to upstream rather than origin

use std::fs;
use std::path::Path;
use std::process::Command;
use tempfile::TempDir;

fn main() {
    // Create a temporary directory for our test
    let temp_dir = TempDir::new().unwrap();
    let test_dir = temp_dir.path();

    // Initialize a bare git repository as upstream
    let upstream_dir = temp_dir.path().join("upstream.git");
    std::fs::create_dir(&upstream_dir).unwrap();

    let git_repo = gix::init_bare(&upstream_dir).unwrap();

    // Create a commit and set up main branch
    let commit_result = git::add_commit(
        &git_repo,
        "refs/heads/main",
        "test.txt",
        b"test content",
        "Initial commit",
        &[],
    );

    // Set up HEAD to point to main
    git::set_head_to_id(&git_repo, commit_result.commit_id);

    // Now clone the upstream repo to create a fork with origin/upstream setup
    let fork_dir = temp_dir.path().join("fork");
    std::fs::create_dir(&fork_dir).unwrap();

    // Clone upstream repo to create fork
    let fork_git_repo = gix::clone(
        upstream_dir.to_str().unwrap(),
        fork_dir.as_path(),
        gix::progress::Discard,
        gix::clone::PrepareFetch::default(),
    ).unwrap();

    // Set up origin (the fork) and upstream (original) remotes
    // In a typical fork scenario, origin points to the fork, upstream to the original
    let _ = fork_git_repo.remote(
        "origin",
        upstream_dir.to_str().unwrap(), // Simulate fork pointing back to upstream
    );

    let _ = fork_git_repo.remote(
        "upstream",
        upstream_dir.to_str().unwrap(), // Same as origin for this test
    );

    // Create remote tracking branches
    fork_git_repo.reference(
        "refs/remotes/origin/main",
        commit_result.commit_id,
        gix::refs::transaction::PreviousValue::MustNotExist,
        "origin/main",
    ).unwrap();

    fork_git_repo.reference(
        "refs/remotes/upstream/main",
        commit_result.commit_id,
        gix::refs::transaction::PreviousValue::MustNotExist,
        "upstream/main",
    ).unwrap();

    // Set up symbolic references
    git::set_symbolic_reference(
        &fork_git_repo,
        "refs/remotes/origin/HEAD",
        "refs/remotes/origin/main",
    );

    git::set_symbolic_reference(
        &fork_git_repo,
        "refs/remotes/upstream/HEAD",
        "refs/remotes/upstream/main",
    );

    // Now run jj git init --colocate in the fork directory
    let output = Command::new("jj")
        .args(["git", "init", "--colocate"])
        .current_dir(&fork_dir)
        .output()
        .expect("Failed to run jj git init");

    println!("jj git init stderr:\n{}", String::from_utf8_lossy(&output.stderr));
    println!("jj git init stdout:\n{}", String::from_utf8_lossy(&output.stdout));

    // Check the repo config to see what trunk() alias was set to
    let jj_config_path = fork_dir.join(".jj").join("repo").join("config.toml");

    if jj_config_path.exists() {
        let config_content = fs::read_to_string(&jj_config_path).unwrap();
        println!("JJ Config content:\n{}", config_content);

        // After our fix, trunk() should be set to main@upstream
        if config_content.contains("trunk() = \"main@upstream\"") {
            println!("SUCCESS: trunk() alias is correctly set to upstream!");
        } else if config_content.contains("trunk() = \"main@origin\"") {
            println!("FAILURE: trunk() alias is still set to origin instead of upstream");
        } else {
            println!("UNKNOWN: trunk() alias not found or set to unexpected value");
        }
    } else {
        println!("ERROR: JJ repo config not found at {:?}", jj_config_path);
    }
}

